// library/debug/index.js — generated by new-action.js, do not edit by hand
import { run as inventoryDumpRun } from './inventoryDump/library.js';

const categoryMeta = await fetch(new URL('./category.json', import.meta.url)).then(r => r.json());
const inventoryDumpMeta = await fetch(new URL('./inventoryDump/action.json', import.meta.url)).then(r => r.json());

export const debugCategory = {
  name: `library/${categoryMeta.id}`,
  install(app) {
    app.registerCategory(categoryMeta, {
      [inventoryDumpMeta.id]: { ...inventoryDumpMeta, run: inventoryDumpRun },
    });
  },
};
